#include <stdio.h>
#include <stdlib.h>

// Structure to represent a meeting
typedef struct Meeting {
    int start;
    int end;
    int index;
} Meeting;

// Comparison function for sorting meetings
int compareMeetings(const void *a, const void *b) {
    Meeting *m1 = (Meeting *)a;
    Meeting *m2 = (Meeting *)b;
    return m1->end - m2->end;
}

// Function to find the maximum number of meetings that can be accommodated
void maxMeetings(int start[], int end[], int n) {
    Meeting meetings[n];
    for (int i = 0; i < n; i++) {
        meetings[i].start = start[i];
        meetings[i].end = end[i];
        meetings[i].index = i + 1;
    }

    qsort(meetings, n, sizeof(Meeting), compareMeetings);

    printf("%d ", meetings[0].index);
    int lastEnd = meetings[0].end;
    for (int i = 1; i < n; i++) {
        if (meetings[i].start > lastEnd) {
            printf("%d ", meetings[i].index);
            lastEnd = meetings[i].end;
        }
    }
    printf("\n");
}

int main() {
    int start[] = {1, 3, 0, 5, 8, 5};
    int end[] = {2, 4, 6, 7, 9, 9};
    int n = sizeof(start) / sizeof(start[0]);
    maxMeetings(start, end, n);
    return 0;
}

